'use client';

import { useRouter } from 'next/navigation';
import type { AwsCredentialIdentity } from '@aws-sdk/types';
import { S3BrowserComponent } from '../src/S3BrowserComponent';

async function credentialsProvider(): Promise<AwsCredentialIdentity> {
  const res = await fetch('/api/credentials');
  if (!res.ok) {
    const body = await res.json().catch(() => ({}));
    throw new Error(body.error ?? 'Failed to fetch AWS credentials from server');
  }
  const { accessKeyId, secretAccessKey, sessionToken } = await res.json();
  return { accessKeyId, secretAccessKey, sessionToken };
}

export default function Home() {
  const router = useRouter();

  return (
    <S3BrowserComponent
      region={process.env.NEXT_PUBLIC_AWS_REGION || 'us-east-1'}
      credentialsProvider={credentialsProvider}
      onOpenInEditor={(bucket, key) =>
        router.push(`/editor?bucket=${encodeURIComponent(bucket)}&key=${encodeURIComponent(key)}`)
      }
    />
  );
}
